import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { DesignIn } from '../../data/models';

@Component({
  selector: 'app-design-ins',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './design-ins.component.html',
  styleUrl: './design-ins.component.css',
})
export class DesignInsComponent {
  readonly stages: DesignIn['stage'][] = ['identified', 'specified', 'basis-of-design', 'bidding', 'booked'];

  cardsForStage(stage: DesignIn['stage']): DesignIn[] {
    return this.seed.designIns().filter((d) => d.stage === stage);
  }

  countForStage(stage: DesignIn['stage']): number {
    return this.cardsForStage(stage).length;
  }

  alerts = computed(() => this.seed.designIns().filter((d) => d.protectionAlert));

  bookedCount = computed(() => this.seed.designIns().filter((d) => d.stage === 'booked').length);
  totalCount = computed(() => this.seed.designIns().length);
  captureRate = computed(() => {
    const total = this.totalCount();
    return total === 0 ? 0 : Math.round((this.bookedCount() / total) * 100);
  });

  stageLabel(stage: DesignIn['stage']): string {
    return stage === 'basis-of-design'
      ? 'Basis of Design'
      : stage.charAt(0).toUpperCase() + stage.slice(1);
  }

  constructor(public seed: SeedService) {}
}
